import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Professional Services","description":"","frontmatter":{"title":"Professional Services","slug":"professional-services"},"headers":[],"relativePath":"account-hub/professional-services.md","filePath":"account-hub/professional-services.md"}'),s={name:"account-hub/professional-services.md"};function n(i,e,c,l,u,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch’s Professional Services offer expert support to optimize your setup, accelerate integration, and drive growth.</p><p>Through specialized onboarding, technical audits, and ongoing consulting, our team of experts help Fortune 500 companies and startups build powerful user experiences with industry-leading services.</p><p>Branch is committed to delivering value, support, and a quality product setup to your team.</p><p>We want to see you succeed, right from the start.</p><h2 id="value" tabindex="-1">Value <a class="header-anchor" href="#value" aria-label="Permalink to &quot;Value&quot;">​</a></h2><p>Our team helps you onboard faster, implement new use cases, and optimize campaigns across key channels like email and paid ads.</p><p>Whether solving complex challenges or offering ongoing guidance, we provide the expertise you need to achieve your business goals.</p><p>With Professional Services from Branch, you can define your integration strategy, onboarding plan, and scope with guidance from our consultants and architects.</p><p>We&#39;ll help you unlock Branch&#39;s full potential with proven best practices and tailored onboarding documentation specific to your needs.</p><p>Count on us to help you solve complex implementation challenges with personalized guidance and advanced technical support.</p><h2 id="contracts" tabindex="-1">Contracts <a class="header-anchor" href="#contracts" aria-label="Permalink to &quot;Contracts&quot;">​</a></h2><p>To ensure a successful setup, all customers who purchase a Branch Growth Platform product must have Professional Services hours included in their contract.</p><p>This way, Branch can reliably guarantee quality support for your onboarding, implementation, and enablement experiences. Do things right the first time and spend your valuable time getting the most out of our product.</p><h2 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h2><p>When you&#39;re ready to discuss Branch packaging, contact our <a href="https://www.branch.io/contact-sales" target="_blank" rel="noreferrer">sales team</a> to get started!</p>',16)])])}const m=a(s,[["render",n]]);export{h as __pageData,m as default};
